BEGIN TRANSACTION;

CREATE TABLE IF NOT EXISTS "user" (
    "id" INTEGER NOT NULL,
    "username" VARCHAR(80) NOT NULL,
    "pw_hash" VARCHAR(255) NOT NULL,
    "role" VARCHAR(20),
    "pref_num_questions" INTEGER,
    "pref_time_per_q" INTEGER,
    "nickname" VARCHAR(120),
    "email" VARCHAR(120),
    "must_change_password" BOOLEAN DEFAULT FALSE,
    "is_deleted" BOOLEAN DEFAULT FALSE,
    "last_score" INTEGER,
    "last_total" INTEGER,
    "play_count" INTEGER DEFAULT 0,
    "created_at" TIMESTAMP,
    "trial_start" TIMESTAMP,
    "trial_end" TIMESTAMP,
    "status" VARCHAR(20) DEFAULT 'pending',
    "email_verified" BOOLEAN DEFAULT FALSE,
    "email_verified_at" TIMESTAMP,
    "activation_token" VARCHAR(255),
    "activation_sent_at" TIMESTAMP,
    "member" TEXT DEFAULT 'BASIC',
    "pending_plan_code" TEXT,
    "pending_months" INTEGER,
    "pending_amount" INTEGER,
    "pending_memo" TEXT,
    "pending_at" TEXT,
    "pending_member" VARCHAR(50),
    "pending_member_name" VARCHAR(120),
    "pending_approve_token" VARCHAR(255),
    "active_until" TIMESTAMP,
    "approved_at" TIMESTAMP,
    "pending_discount" INTEGER DEFAULT 0,
    "pending_final_total" INTEGER DEFAULT 0,
    "pending_duration_label" TEXT,
    PRIMARY KEY ("id"),
    UNIQUE ("username")
);

CREATE TABLE IF NOT EXISTS "access_setting" (
    "id" INTEGER NOT NULL,
    "mode" VARCHAR(20) NOT NULL,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "set" (
    "id" INTEGER NOT NULL,
    "title" VARCHAR(200) NOT NULL,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "topic" (
    "id" INTEGER NOT NULL,
    "set_id" INTEGER NOT NULL,
    "name" VARCHAR(200) NOT NULL,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("set_id") REFERENCES "set"("id")
);

CREATE TABLE IF NOT EXISTS "folder" (
    "id" INTEGER NOT NULL,
    "name" VARCHAR(200) NOT NULL,
    "parent_id" INTEGER,
    "level" INTEGER,
    "image" TEXT,
    "order_index" INTEGER,
    "is_active_practice" INTEGER DEFAULT 1,
    "member_plans" VARCHAR(100) DEFAULT 'FREE,BASIC,PRO,VIP',
    PRIMARY KEY ("id"),
    FOREIGN KEY ("parent_id") REFERENCES "folder"("id")
);

CREATE TABLE IF NOT EXISTS "edu_folders" (
    "id" INTEGER NOT NULL,
    "name" VARCHAR(255) NOT NULL,
    "image" VARCHAR(255),
    "level" INTEGER NOT NULL,
    "parent_id" INTEGER,
    "position" INTEGER,
    "created_at" TIMESTAMP,
    "is_active" INTEGER DEFAULT 1,
    "order" INTEGER DEFAULT 0,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("parent_id") REFERENCES "edu_folders"("id")
);

CREATE TABLE IF NOT EXISTS "question" (
    "id" INTEGER NOT NULL,
    "folder_id" INTEGER,
    "text" TEXT NOT NULL,
    "topic_id" INTEGER,
    "type" TEXT DEFAULT 'mcq',
    "member_plans" VARCHAR(100) DEFAULT 'FREE,BASIC,PRO,VIP',
    "answer_1" TEXT,
    "answer_2" TEXT,
    "answer_3" TEXT,
    "answer_4" TEXT,
    "answer_5" TEXT,
    "answer_6" TEXT,
    "answer_7" TEXT,
    "answer_8" TEXT,
    "answer_9" TEXT,
    "answer_10" TEXT,
    "answer_11" TEXT,
    "answer_12" TEXT,
    "answer_count" INTEGER DEFAULT 0,
    "correct_indexes" TEXT,
    "correct_answers_text" TEXT,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("folder_id") REFERENCES "folder"("id"),
    FOREIGN KEY ("topic_id") REFERENCES "topic"("id")
);

CREATE TABLE IF NOT EXISTS "choice" (
    "id" INTEGER NOT NULL,
    "question_id" INTEGER NOT NULL,
    "text" TEXT NOT NULL,
    "is_correct" INTEGER,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("question_id") REFERENCES "question"("id")
);



CREATE TABLE IF NOT EXISTS "lessons" (
    "id" INTEGER NOT NULL,
    "title" VARCHAR(255) NOT NULL,
    "slug" VARCHAR(255) NOT NULL,
    "image" VARCHAR(255),
    "folder3_id" INTEGER NOT NULL,
    "order" INTEGER,
    "created_at" TIMESTAMP,
    "is_active" INTEGER,
    "sections" TEXT,
    "pdf" VARCHAR(255) DEFAULT 'Bai_hoc.pdf',
    "review_type" VARCHAR(20) DEFAULT 'pdf',
    "source_url" TEXT,
    "drive_kind" TEXT DEFAULT 'pdf',
    "file_name" TEXT,
    "member_plans" VARCHAR(100) DEFAULT 'FREE,BASIC,PRO,VIP',
    PRIMARY KEY ("id"),
    UNIQUE ("slug"),
    FOREIGN KEY ("folder3_id") REFERENCES "edu_folders"("id")
);

CREATE TABLE IF NOT EXISTS "login_log" (
    "id" INTEGER NOT NULL,
    "username" VARCHAR(80),
    "ip" VARCHAR(50),
    "status" VARCHAR(30),
    "created_at" TIMESTAMP,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "login_log_summary" (
    "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "username" VARCHAR(80) UNIQUE,
    "last_ip" VARCHAR(50),
    "last_at" TIMESTAMP,
    "success_count" INTEGER DEFAULT 0,
    "failed_count" INTEGER DEFAULT 0,
    "blocked_count" INTEGER DEFAULT 0,
    "locked_count" INTEGER DEFAULT 0,
    "wait_accept_count" INTEGER DEFAULT 0,
    "expired_count" INTEGER DEFAULT 0,
    "wait_renew_count" INTEGER DEFAULT 0
);

CREATE TABLE IF NOT EXISTS "notifications" (
    "id" INTEGER NOT NULL,
    "role" VARCHAR(20) NOT NULL,
    "user_id" INTEGER,
    "title" VARCHAR(255) NOT NULL,
    "message" TEXT,
    "target_url" VARCHAR(500),
    "icon" VARCHAR(20),
    "is_read" INTEGER,
    "created_at" TIMESTAMP,
    "action_type" TEXT,
    "ref_user_id" INTEGER,
    "ref_plan_code" TEXT,
    "ref_months" INTEGER,
    "is_done" INTEGER DEFAULT 0,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("user_id") REFERENCES "user"("id")
);

CREATE TABLE IF NOT EXISTS "attempt" (
    "id" INTEGER NOT NULL,
    "user_id" INTEGER NOT NULL,
    "topic_id" INTEGER NOT NULL,
    "created_at" TIMESTAMP,
    "finished_at" TIMESTAMP,
    "question_count" INTEGER,
    "time_per_q" INTEGER,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("user_id") REFERENCES "user"("id"),
    FOREIGN KEY ("topic_id") REFERENCES "topic"("id")
);

CREATE TABLE IF NOT EXISTS "attempt_answer" (
    "id" INTEGER NOT NULL,
    "attempt_id" INTEGER NOT NULL,
    "question_id" INTEGER NOT NULL,
    "chosen_choice_id" INTEGER,
    "is_correct" INTEGER,
    "answered" INTEGER,
    "chosen_choice_ids" TEXT,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("attempt_id") REFERENCES "attempt"("id"),
    FOREIGN KEY ("question_id") REFERENCES "question"("id")
);

CREATE TABLE IF NOT EXISTS "access_allow" (
    "id" INTEGER NOT NULL,
    "user_id" INTEGER NOT NULL,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("user_id") REFERENCES "user"("id")
);









