INSERT INTO "question" VALUES (119,6,'Công tác tổ chức các kỳ thi thăng cấp đai Taekwondo hiện nay sẽ như thế nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','VTF sẽ trực tiếp điều hành và công nhận kết quả kỳ thi thăng cấp của các CLB/Võ đường/Công ty/Điểm tập ở địa phương không có Liên đoàn/Hội Taekwondo cấp tỉnh.','Các CLB/Võ đường/Công ty/Điểm tập không được phép tự tổ chức các cuộc thi thăng cấp đai, đẳng Taekwondo khi chưa được phép của VTF. Nếu cố tình tổ chức, kết quả kỳ thi sẽ không được công nhận và sẽ bị xóa mã CLB trên hệ thống quản lý online của VTF và HLV sẽ bị xử lý kỷ luật theo Điều 13 của Quy định thi thăng cấp, đẳng VTF','Kết quả các kỳ thi thăng cấp chỉ được công nhận khi đăng ký trực tuyến và được Liên đoàn, các tổ chức thành viên cử giám sát, giám khảo làm nhiệm vụ công khai trên phần mềm quản lý thi thăng cấp Taekwondo của Liên đoàn.','Cả 3 đáp án trên',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Cả 3 đáp án trên');
