INSERT INTO "question" VALUES (121,7,'Trong thi đấu chuyên nghiệp, VĐV vô tình uống thuốc cảm cúng có chứa chất cấm (Doping) và bị phát hiện dương tính. VĐV đó có bị vi phạm không?',NULL,'mcq','FREE,BASIC,PRO,VIP','Không! Vì không cố ý.','Có, Vì sử dụng Doping là lỗi khách quan, không phân biệt vô ý hay cố ý.','Chỉ bị nhắc nhở nếu vi phạm lần đầu','Phụ thuộc vào giải trình của huấn luyện viên',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Có, Vì sử dụng Doping là lỗi khách quan, không phân biệt vô ý hay cố ý.');
