INSERT INTO "question" VALUES (169,6,'Tổ chức thành viên, hội viên, võ sinh Taekwondo nếu vi phạm một trong những điều nào sẽ bị hạ bậc đẳng, cấp hiện có hoặc tước toàn bộ đẳng, cấp và đình chỉ tư cách hội viên?',NULL,'multi','FREE,BASIC,PRO,VIP','Sửa đổi các nội dung của văn bằng; làm bằng gian, bằng giả.','Có hành vi gian lận trong các cuộc thi lên cấp, đẳng.','Vi phạm quy tắc đạo đức của Liên đoàn.','Tổ chức các cuộc thi thăng cấp, đẳng mà không được sự cho phép của Liên đoàn.','Tham gia mua bán, cho tặng, cấp các loại văn bằng Taekwondo không có giá trị sử dụng tại Việt Nam (Văn bằng VTF) và trên thế giới (Văn bằng Kukkiwon).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,5,'1,2,3,4,5','Có hành vi gian lận trong các cuộc thi lên cấp, đẳng.||Sửa đổi các nội dung của văn bằng; làm bằng gian, bằng giả.||Tham gia mua bán, cho tặng, cấp các loại văn bằng Taekwondo không có giá trị sử dụng tại Việt Nam (Văn bằng VTF) và trên thế giới (Văn bằng Kukkiwon).||Tổ chức các cuộc thi thăng cấp, đẳng mà không được sự cho phép của Liên đoàn.||Vi phạm quy tắc đạo đức của Liên đoàn.');
