INSERT INTO "question" VALUES (205,24,'Kỹ thuật nào sau đây trong quyền sáng tạo (Freesstyle) trong nội dung đồng đội sẽ áp dụng thêm đá vỡ mục tiêu (Breaking)?',NULL,'multi','FREE,BASIC,PRO,VIP','Kỹ thuật đá chậm (Basic kick)','Bay đá ngang (Jumping kick)','Bay đá nhiều mục tiêu (Multiple kicks)','Xoay đá (Tonado kicks)','Đá đối kháng (Consecutive kicks)','Nhào lộn có đá (Acrobatic)','Combo intro (Tổ hợp nhiều động tác đá khó)',NULL,NULL,NULL,NULL,NULL,7,'4,5,6','Nhào lộn có đá (Acrobatic)||Xoay đá (Tonado kicks)||Đá đối kháng (Consecutive kicks)');
INSERT INTO "question" VALUES (206,24,'Trong nội dung thi đấu quyền sáng tạo đồng đội, số lượng ván tối thiểu cần phải đá vỡ trong kỹ thuật đá xoay (Spining kicks) là bao nhiêu tấm?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 tấm','2 tấm','3 tấm','4 tấm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','1 tấm');
INSERT INTO "question" VALUES (207,24,'Trong nội dung thi đấu quyền sáng tạo đồng đội, số lượng ván tối thiểu cần phải đá vỡ trong kỹ thuật nhào lộn có đá (Acrobatic) là bao nhiêu tấm?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 tấm','2 tấm','3 tấm','4 tấm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','1 tấm');
INSERT INTO "question" VALUES (208,24,'Trong nội dung thi đấu quyền sáng tạo đồng đội, số lượng ván tối thiểu cần phải đá vỡ trong kỹ thuật đá đối kháng (Consecutive Kicks) là bao nhiêu tấm?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 tấm','2 tấm','3 tấm','4 tấm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','3 tấm');
INSERT INTO "question" VALUES (209,24,'Điểm số của phần kỹ thuật(Accuracy) và trình bày(Presentation) trong bài Poomsae tiêu chuẩn là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','6.0 Accuracy và 4.0 Presentation','4.0 Accuracy và 6.0 Presentation','7.0 Accuracy và 3.0 Presentation','3.0 Accuracy và 7.0 Presentation',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','4.0 Accuracy và 6.0 Presentation');
INSERT INTO "question" VALUES (210,24,'Điểm số của phần kỹ thuật(Accuracy) và trình bày(Presentation) trong bài quyền sáng tạo (Freestyle) là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','6.0 Accuracy và 4.0 Presentation','4.0 Accuracy và 6.0 Presentation','7.0 Accuracy và 3.0 Presentation','3.0 Accuracy và 7.0 Presentation',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','6.0 Accuracy và 4.0 Presentation');
INSERT INTO "question" VALUES (211,24,'Mỗi lỗi lớn (Major Mistake) về kỹ thuật sẽ bị trừ bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','0.1','0.3','0.5','1.0',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','0.3');
INSERT INTO "question" VALUES (212,24,'Mỗi lỗi nhỏ (Minor Mistake) về kỹ thuật sẽ bị trừ bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','0.01','0.05','0.1','0.3',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','0.1');
INSERT INTO "question" VALUES (213,24,'Hành động nào sau đây được coi là lỗi nhỏ (-0.1)?',NULL,'mcq','FREE,BASIC,PRO,VIP','Thực hiện sai động tác','Nhìn sai hướng','Hét Kihap sai thời điểm.','Sai vị trí khởi đầu cao thấp',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Sai vị trí khởi đầu cao thấp');
INSERT INTO "question" VALUES (214,24,'Trường hợp nào sau đây bị trừ lỗi lớn (-0.3)?',NULL,'mcq','FREE,BASIC,PRO,VIP','Đá trước chân trụ xoay quá 45 độ','VĐV bị mất thăng bằng nhưng không ngã.','Thực hiện sai động tác đã quy định','Cả B và C đều đúng.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Cả B và C đều đúng.');
INSERT INTO "question" VALUES (215,24,'Nếu VĐV kết thúc bài quyền tiêu chuẩn sai vị trí bắt đầu quá một bàn chân, lỗi này bị trừ:',NULL,'mcq','FREE,BASIC,PRO,VIP','0.1','0.3','0.5','Không trừ điểm vì đã trừ trong bài',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Không trừ điểm vì đã trừ trong bài');
INSERT INTO "question" VALUES (216,24,'Điểm trình bày được chia thành 3 phần, mỗi phần tối đa bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','1.0','1.5','2.0','3.0',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','2.0');
INSERT INTO "question" VALUES (217,23,'Kích thước tiêu chuẩn của Khu vực thi đấu (Contest Area) hình bát giác là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','6m x 6m','8m x 8m','10m x 10m','12m x 12m',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','8m x 8m');
INSERT INTO "question" VALUES (218,23,'Khu vực cảnh báo (Alert Area) được quy định có chiều rộng bao nhiêu và nằm ở đâu?',NULL,'mcq','FREE,BASIC,PRO,VIP','Rộng 1m, nằm bên ngoài đường biên (Boundary Line).','Rộng 60cm, nằm bên ngoài đường biên.','Rộng 50cm, nằm bên trong tính từ mép ngoài Khu vực thi đấu hướng vào tâm.','Rộng 60cm, nằm bên trong tính từ mép ngoài Khu vực thi đấu hướng vào tâm.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Rộng 60cm, nằm bên trong tính từ mép ngoài Khu vực thi đấu hướng vào tâm.');
INSERT INTO "question" VALUES (219,23,'Sàn thi đấu (Contest Area) hình bát giác có đường kính khoảng bao nhiêu mét?',NULL,'mcq','FREE,BASIC,PRO,VIP','6m','8m','10m','12m',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','8m');
INSERT INTO "question" VALUES (220,23,'Trong sân thi đấu hình bát giác, độ dài mỗi cạnh của hình bát giác là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','Khoảng 2.5m','Khoảng 3.0m','Khoảng 3.3m','Khoảng 3.5m',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Khoảng 3.3m');
INSERT INTO "question" VALUES (221,23,'Nếu sàn thi đấu được lắp đặt trên bệ cao (platform), chiều cao cho phép của bệ là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','0.4m – 0.6m','0.5m – 1.0m','0.6m – 1.0m','1.0m – 1.2m',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','0.6m – 1.0m');
INSERT INTO "question" VALUES (222,23,'Đường bao quanh bên ngoài của Khu vực thi đấu (Contest Area) được gọi là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Outer Line (Đường bao ngoài).','Safety Line (Đường an toàn).','Limit Line (Đường giới hạn).','Boundary Line (Đường giới hạn/Đường biên).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Boundary Line (Đường giới hạn/Đường biên).');
INSERT INTO "question" VALUES (223,23,'Vị trí của Huấn luyện viên (Coach) được quy định đặt ở đâu?',NULL,'mcq','FREE,BASIC,PRO,VIP','Cách tâm đường biên ngoài (Outer Line) tối thiểu 2m.','Cách tâm đường biên ngoài (Outer Line) tối thiểu 1m.','Ngay sát góc của Khu vực thi đấu.','Bên cạnh bàn Thư ký (Recorder’s Desk).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Cách tâm đường biên ngoài (Outer Line) tối thiểu 2m.');
INSERT INTO "question" VALUES (224,23,'Độ nghiêng của phần bên ngoài Đường bao ngoài (Outer Line) để đảm bảo an toàn cho VĐV phải nhỏ hơn bao nhiêu độ?',NULL,'mcq','FREE,BASIC,PRO,VIP','15 độ','20 độ','25 độ','30 độ',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','30 độ');
INSERT INTO "question" VALUES (225,23,'Tổng diện tích của Sân thi đấu (Competition Area), bao gồm cả Khu vực thi đấu và Khu vực an toàn, phải nằm trong khoảng kích thước nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Không nhỏ hơn 8m x 8m và không lớn hơn 10m x 10m.','Cố định là 10m x 10m.','Không nhỏ hơn 10m x 10m và không lớn hơn 12m x 12m.','Không nhỏ hơn 12m x 12m và không lớn hơn 14m x 14m.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Không nhỏ hơn 10m x 10m và không lớn hơn 12m x 12m.');
INSERT INTO "question" VALUES (226,23,'Màu sắc quy định của bảo hộ răng cho VĐV thi đấu là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Chỉ được màu trắng.','Chỉ được màu trong suốt.','Màu trắng hoặc trong suốt.','Màu bất kỳ miễn là không có màu đỏ.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Màu trắng hoặc trong suốt.');
INSERT INTO "question" VALUES (227,23,'Tại buổi cân chính thức (General Weigh-in), nếu VĐV không đạt trọng lượng trong lần cân đầu tiên, họ có quyền lợi gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Bị loại ngay lập tức.','Được phép cân thêm 1 lần nữa trong thời gian quy định của buổi cân.','Được phép cân lại bao nhiêu lần tùy thích trong vòng 1 tiếng.','Bị trừ 1 điểm Gam-jeom khi bắt đầu trận đấu.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Được phép cân thêm 1 lần nữa trong thời gian quy định của buổi cân.');
INSERT INTO "question" VALUES (228,23,'Trong buổi cân ngẫu nhiên (Random Weigh-in) diễn ra vào buổi sáng ngày thi đấu, mức dung sai trọng lượng cho phép là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','Đúng theo hạng cân','Cộng thêm 2%.','Cộng thêm 5%.','Cộng thêm 500 gram.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Cộng thêm 5%.');
INSERT INTO "question" VALUES (229,23,'Thời gian nghỉ giữa các hiệp đấu (Rest period) tiêu chuẩn là bao lâu?',NULL,'mcq','FREE,BASIC,PRO,VIP','30 giây','45 giây','60 giây','90 giây',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','60 giây');
INSERT INTO "question" VALUES (230,23,'Nếu tỷ số hòa sau 3 hiệp chính (hoặc sau hiệp 3 trong thể thức Best of 3 có tính tổng điểm), hiệp phụ (Golden Round) sẽ diễn ra trong bao lâu?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 phút.','1 phút 30 giây','2 phút','Không giới hạn thời gian cho đến khi có người ghi điểm.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','1 phút.');
INSERT INTO "question" VALUES (231,23,'Trong hiệp phụ (Golden Round), điều kiện để chiến thắng là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Ghi được 2 điểm trước hoặc đối thủ bị 2 Gam-jeom.','Ghi được bất kỳ điểm số nào trước (Golden Point).','Ghi được 3 điểm trước.','Hết giờ ai nhiều điểm hơn thì thắng.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Ghi được 2 điểm trước hoặc đối thủ bị 2 Gam-jeom.');
INSERT INTO "question" VALUES (232,23,'Theo quy định về kỹ thuật cho phép, đòn đấm (Fist technique) phải sử dụng phần nào của bàn tay?',NULL,'mcq','FREE,BASIC,PRO,VIP','Bất kỳ phần nào của nắm tay.','Cạnh bàn tay (dao tay).','Lòng bàn tay.','Mặt trước của nắm tay (phần các đốt ngón tay trỏ và giữa) nắm chặt.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Mặt trước của nắm tay (phần các đốt ngón tay trỏ và giữa) nắm chặt.');
INSERT INTO "question" VALUES (233,23,'Đòn tấn công bằng chân (Foot technique) được phép sử dụng phần nào của chân?',NULL,'mcq','FREE,BASIC,PRO,VIP','Bất kỳ phần nào từ đầu gối trở xuống.','Chỉ bàn chân.','Bất kỳ phần nào của chân dưới mắt cá chân (ankle bone).','Chỉ mu bàn chân.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Bất kỳ phần nào của chân dưới mắt cá chân (ankle bone).');
INSERT INTO "question" VALUES (234,23,'Theo luật sửa đổi (2026), điểm số cho đòn đá quay trúng đầu (Turning kick to the head) là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','3 điểm','4 điểm','5 điểm','6 điểm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','5 điểm');
INSERT INTO "question" VALUES (235,23,'Đòn đá trúng giáp thân (Body kick) thông thường được tính bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 điểm','2 điểm','3 điểm','4 điểm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','2 điểm');
INSERT INTO "question" VALUES (236,23,'Một "Gam-jeom" (điểm phạt) được tính như thế nào vào điểm số?',NULL,'mcq','FREE,BASIC,PRO,VIP','Cộng 1 điểm cho đối thủ.','Trừ 1 điểm của người phạm lỗi.','Trừ 0.5 điểm của người phạm lỗi.','Không trừ điểm, chỉ tính số lần cảnh cáo.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Cộng 1 điểm cho đối thủ.');
INSERT INTO "question" VALUES (237,23,'VĐV sẽ bị xử thua (PUN - Punitive Declaration) nếu nhận bao nhiêu Gam-jeom trong toàn trận đấu?',NULL,'mcq','FREE,BASIC,PRO,VIP','5 Gam-jeom.','8 Gam-jeom.','10 Gam-jeom.','12 Gam-jeom.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','10 Gam-jeom.');
INSERT INTO "question" VALUES (238,23,'Hành vi nào sau đây KHÔNG bị phạt Gam-jeom?',NULL,'mcq','FREE,BASIC,PRO,VIP','Ngã (Falling down) do đòn tấn công hợp lệ của đối phương.','Bước một chân ra khỏi đường biên (Boundary Line).','Tránh né trận đấu (Avoiding the match).','Ôm hoặc đẩy đối thủ (Grabbing or pushing).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Ngã (Falling down) do đòn tấn công hợp lệ của đối phương.');
INSERT INTO "question" VALUES (239,23,'Việc "Nâng chân để chặn đòn" (Lifting the leg to block) sẽ KHÔNG bị phạt trong trường hợp nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Khi chân nâng lên cao quá thắt lưng.','Khi chân nâng lên và giữ yên trong 3 giây.','Khi hành động đó được nối tiếp ngay bằng đòn tấn công (đá hoặc đấm).','Khi đối thủ đang lao vào tấn công.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Khi hành động đó được nối tiếp ngay bằng đòn tấn công (đá hoặc đấm).');
INSERT INTO "question" VALUES (240,23,'Trong thể thức "Best of 3" (Thắng 2/3 hiệp), nếu điểm số hòa khi kết thúc hiệp, tiêu chí đầu tiên để xét thắng hiệp đó là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Số lần đấm trúng đích.','Điểm số ghi được nhiều nhất từ các đòn đá quay/xoay (Turning/Spinning kick).','Số lượng Gam-jeom ít hơn.','Số lần ra đòn trúng giáp (Hits registered) nhiều hơn.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Điểm số ghi được nhiều nhất từ các đòn đá quay/xoay (Turning/Spinning kick).');
INSERT INTO "question" VALUES (241,23,'Trọng tài trung tâm sẽ tuyên bố gì để tạm dừng trận đấu?',NULL,'mcq','FREE,BASIC,PRO,VIP','"Keu-man"','"Kal-yeo"','"Kye-sok"','"Shi-gan"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','"Kal-yeo"');
INSERT INTO "question" VALUES (242,23,'Nếu một VĐV bị ngã và trọng tài đếm đến "Yeo-dul" (8), nhưng VĐV đó không thể hiện tư thế sẵn sàng thi đấu (Fighting position), trọng tài sẽ làm gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Đếm tiếp đến 10 ("Yeol") rồi tuyên bố thua.','Tuyên bố đối phương thắng cuộc (RSC) ngay lập tức.','Hỏi VĐV "Are you okay?" một lần nữa.','Cho gọi bác sĩ vào sân.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Đếm tiếp đến 10 ("Yeol") rồi tuyên bố thua.');
INSERT INTO "question" VALUES (243,23,'Trong 5 giây cuối cùng của hiệp đấu, trọng tài có thể tự mình yêu cầu IVR để kiểm tra điều gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Điểm số đòn đá quay.','Điểm số đòn đấm.','Các lỗi phạt (Gam-jeom) như ngã, ra biên, tấn công sau lệnh dừng.','Xem lại thời gian thi đấu.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Các lỗi phạt (Gam-jeom) như ngã, ra biên, tấn công sau lệnh dừng.');
INSERT INTO "question" VALUES (244,23,'Trong buổi cân chính thức (General Weigh-in), VĐV Nam được phép mặc trang phục gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Phải khỏa thân hoàn toàn.','Quần đùi thể thao.','Võ phục.','Quần lót (Underpants).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Quần lót (Underpants).');
INSERT INTO "question" VALUES (245,23,'Khẩu lệnh nào được trọng tài sử dụng để yêu cầu nhân viên y tế vào sân sơ cứu cho VĐV bị thương?',NULL,'mcq','FREE,BASIC,PRO,VIP','"Kal-yeo"','"Keu-man"','"Shi-gan"','"Kye-shi"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','"Kye-shi"');
INSERT INTO "question" VALUES (246,23,'Để yêu cầu hai VĐV thi đấu tích cực hơn (tránh thụ động), trọng tài sử dụng khẩu lệnh nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','"Fight"','"Si-jak"','"Gong-gyeok"','"Go"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','"Gong-gyeok"');
INSERT INTO "question" VALUES (247,23,'Trong thể thức "Best of 3" (Thắng 2/3 hiệp), nếu điểm số hòa khi kết thúc một hiệp, tiêu chí ĐẦU TIÊN để xác định người thắng hiệp đó là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Điểm số ghi được từ đòn đá quay/xoay (Turning/Spinning kick).','Điểm số từ đòn đá vào đầu.','Điểm số từ đòn đấm.','Số lần hệ thống PSS ghi nhận trúng đích.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Điểm số ghi được từ đòn đá quay/xoay (Turning/Spinning kick).');
INSERT INTO "question" VALUES (248,23,'Trong thể thức "Best of 3", nếu điểm đá quay bằng nhau, thứ tự ưu tiên tiếp theo để xét thắng hiệp là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Ít Gam-jeom hơn -> Điểm đầu -> Điểm thân -> Điểm đấm.','Điểm đầu -> Điểm thân -> Điểm đấm -> Điểm từ Gam-jeom.','Điểm đấm -> Điểm thân -> Điểm đầu.','Số lần PSS ghi nhận trúng đích.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Điểm đầu -> Điểm thân -> Điểm đấm -> Điểm từ Gam-jeom.');
INSERT INTO "question" VALUES (249,23,'Nếu tất cả các tiêu chí kỹ thuật đều bằng nhau trong Hiệp phụ, ai là người quyết định cuối cùng?',NULL,'mcq','FREE,BASIC,PRO,VIP','Tổng trọng tài.','Chỉ Trọng tài trung tâm.','Máy tính của giám sát chọn ngẫu nhiên.','Trọng tài trung tâm và các Giám định (Judges).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Trọng tài trung tâm và các Giám định (Judges).');
INSERT INTO "question" VALUES (250,23,'Trong trường hợp 3 Giám định cùng xét ưu thế nhưng kết quả hòa (ví dụ: 1 chọn Xanh, 1 chọn Đỏ, 1 phiếu trắng), ai sẽ là người quyết định?',NULL,'mcq','FREE,BASIC,PRO,VIP','Trọng tài trung tâm (Referee).','Giám sát kỹ thuật (TD).','Trưởng ban trọng tài.','Hủy kết quả hiệp đó.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Trọng tài trung tâm (Referee).');
INSERT INTO "question" VALUES (251,23,'Nếu một trận đấu phải dừng lại ở hiệp 2 do VĐV bị chấn thương không thể thi đấu tiếp (không do lỗi phạm quy), kết quả sẽ được tính như thế nào trong thể thức Best of 3?',NULL,'mcq','FREE,BASIC,PRO,VIP','VĐV bị chấn thương bị xử thua.','Hủy bỏ kết quả trận đấu.','Tính điểm tại thời điểm dừng trận đấu của hiệp đó để quyết định người thắng hiệp, sau đó tổng hợp kết quả các hiệp.','VĐV đối phương mặc nhiên thắng.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Tính điểm tại thời điểm dừng trận đấu của hiệp đó để quyết định người thắng hiệp, sau đó tổng hợp kết quả các hiệp.');
INSERT INTO "question" VALUES (252,23,'Tại buổi cân chính thức (General Weigh-in), VĐV Nữ bắt buộc phải mặc trang phục gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Quần đùi và áo phông.','Quần lót (Underpants) và áo lót (Brassiere).','Võ phục (Dobok).','Bắt buộc khỏa thân',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Quần lót (Underpants) và áo lót (Brassiere).');
INSERT INTO "question" VALUES (253,23,'Đối với lứa tuổi Cadet (Thiếu niên) và Junior (Trẻ), quy định về trang phục khi cân có điểm gì đặc biệt?',NULL,'mcq','FREE,BASIC,PRO,VIP','Phải cân khỏa thân để chính xác.','Không được trừ bì trọng lượng trang phục.','Được mặc nguyên võ phục.','Phải mặc quần lót (và áo lót với nữ) và được trừ bì (dung sai) 100g.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Phải mặc quần lót (và áo lót với nữ) và được trừ bì (dung sai) 100g.');
INSERT INTO "question" VALUES (254,23,'Giới tính của trọng tài phụ trách cân (Weigh-in Official) phải như thế nào so với VĐV?',NULL,'mcq','FREE,BASIC,PRO,VIP','Có thể là Nam hoặc Nữ.','Chỉ cần là trọng tài quốc tế là được.','Bắt buộc phải cùng giới tính với VĐV (Nam cân cho Nam, Nữ cân cho Nữ).','Do ban tổ chức chỉ định ngẫu nhiên.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Bắt buộc phải cùng giới tính với VĐV (Nam cân cho Nam, Nữ cân cho Nữ).');
INSERT INTO "question" VALUES (255,23,'Nếu một VĐV tham gia hạng cân "Dưới 45kg" (Under 45kg), mức cân tối đa cho phép tại buổi cân chính thức là bao nhiêu (đối với giải Senior không có trừ bì)?',NULL,'mcq','FREE,BASIC,PRO,VIP','45.1kg','45.05kg','45.09kg','45.10kg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','45.09kg');
INSERT INTO "question" VALUES (256,23,'HLV chỉ có thể yêu cầu Video Replay (IVR) cho một hành động diễn ra trong vòng bao nhiêu giây trước đó?',NULL,'mcq','FREE,BASIC,PRO,VIP','3 giây tính từ thời điểm HLV ra hiệu yêu cầu','5 giây tính từ thời điểm HLV ra hiệu yêu cầu','10 giây tính từ thời điểm HLV ra hiệu yêu cầu','Trong hiệp đấu, HLV nhớ thì có thể kiện',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','5 giây tính từ thời điểm HLV ra hiệu yêu cầu');
INSERT INTO "question" VALUES (257,23,'Nếu HLV nghi ngờ hệ thống PSS bị lỗi kỹ thuật (không ghi điểm), họ có thể yêu cầu kiểm tra vào thời điểm nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Bất cứ lúc nào.','Chỉ trong hiệp 1.','Bất cứ lúc nào trong hiệp 2 hoặc hiệp 3.','Chỉ khi hết trận.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Bất cứ lúc nào trong hiệp 2 hoặc hiệp 3.');
INSERT INTO "question" VALUES (258,23,'Khi HLV giơ thẻ yêu cầu IVR, trọng tài trung tâm sẽ làm gì đầu tiên?',NULL,'mcq','FREE,BASIC,PRO,VIP','Ra hiệu cho Giám sát xem video ngay.','Từ chối nếu thấy không hợp lý.','Phạt Gam-jeom HLV.','Đến gần HLV và hỏi lý do khiếu nại.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Đến gần HLV và hỏi lý do khiếu nại.');
INSERT INTO "question" VALUES (259,23,'Trong trường hợp hạng cân có từ 17 đến 32 vận động viên (ví dụ: 25 người), số lượng VĐV phải thực hiện cân ngẫu nhiên là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','4 VĐV','5 VĐV','6 VĐV','7 VĐV',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','6 VĐV');
INSERT INTO "question" VALUES (260,23,'Nếu hạng cân có từ 9 đến 16 vận động viên tham gia, bao nhiêu người sẽ bị gọi tên đi cân ngẫu nhiên?',NULL,'mcq','FREE,BASIC,PRO,VIP','2 VĐV','3 VĐV','4 VĐV','5 VĐV',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','4 VĐV');
INSERT INTO "question" VALUES (261,23,'Đối với các hạng cân ít người, từ 4 đến 8 vận động viên, số lượng chọn cân ngẫu nhiên là bao nhiêu VĐV?',NULL,'mcq','FREE,BASIC,PRO,VIP','Không chọn cân ngẫu nhiên','1 VĐV','2 VĐV','3 VĐV',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','2 VĐV');
INSERT INTO "question" VALUES (262,23,'Nếu VĐV không có mặt để thực hiện cân ngẫu nhiên đúng giờ quy định, hình thức xử phạt là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Bị cảnh cáo.','Bị loại (Disqualified).','Bị trừ điểm khi vào trận.','Được phép cân bù sau đó nhưng phải nộp phạt.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Bị loại (Disqualified).');
INSERT INTO "question" VALUES (263,23,'Nếu một hạng cân có "Trên 32 vận động viên" tham dự, tỷ lệ số lượng VĐV được chọn để cân ngẫu nhiên là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','10% tổng số VĐV.','20% tổng số VĐV.','30% tổng số VĐV.','Cố định 10 người.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','20% tổng số VĐV.');
INSERT INTO "question" VALUES (264,24,'Khi thực hiện động tác đá phía trước(Ap Chagi), lỗi nào sau đây sẽ bị trừ 0.3 điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','Cong chân trụ.','Mở bàn chân trụ quá 45 độ','Gập cổ chân đá','Nhìn xuống đất hoặc gập đầu.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Nhìn xuống đất hoặc gập đầu.');
INSERT INTO "question" VALUES (265,24,'Trong kỹ thuật đá ngang (Yeop Chagi), lỗi nào sau đây sẽ bị trừ 0.3 điểm phần kỹ thuật?',NULL,'mcq','FREE,BASIC,PRO,VIP','Đá mất thăng bằng nhẹ','Xòe lòng bàn tay chống vào đùi chân trụ','Chống tay bằng nắm đấm vào đùi chân trụ','Đá bị ưỡn',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Xòe lòng bàn tay chống vào đùi chân trụ');
INSERT INTO "question" VALUES (266,6,'Kỳ thi Quý I diễn ra trong khoảng thời gian nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Từ 1/1 đến 31/3','Từ 15/1 đến 31/3','Từ 1/2 đến 30/4','15/1 đến 15/4',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Từ 15/1 đến 31/3');
INSERT INTO "question" VALUES (267,6,'Kỳ thi Quý II diễn ra trong khoảng thời gian nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Từ 15/1 đến 31/3','Từ 01/4 đến 30/6','Từ 15/4 đến 30/6','Từ 01/5 đến 30/6',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Từ 15/4 đến 30/6');
INSERT INTO "question" VALUES (268,6,'Kỳ thi Quý III diễn ra trong khoảng thời gian nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Từ 15/07 đến 30/09','Từ 01/07 đến 30/09','Từ 20/07 đến 30/09','Từ 15/07 đến 31/09',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Từ 15/07 đến 30/09');
INSERT INTO "question" VALUES (269,6,'Kỳ thi Quý IV diễn ra trong khoảng thời gian nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Từ 15/10 đến 31/12','Từ 01/10 đến 31/12','Từ 01/11 đến 30/12','Từ 20/10 đến 31/12',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Từ 15/10 đến 31/12');
