INSERT INTO "question" VALUES (273,6,'Ai là người có quyền sửa đổi, bổ sung Quy định thi thăng cấp, đẳng?',NULL,'mcq','FREE,BASIC,PRO,VIP','Chủ tịch VTF','Tổng thư ký VTF','Ban Chấp hành Liên đoàn Taekwondo Việt Nam','Bộ Văn hóa, Thể thao và Du lịch',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Ban Chấp hành Liên đoàn Taekwondo Việt Nam');
INSERT INTO "question" VALUES (274,6,'Theo Điều 13 của Quy định thi thăng cấp, đẳng, bất kỳ tổ chức thành viên, hội viên, hay võ sinh nào vi phạm một trong các điều sau đây sẽ bị xử lý kỷ luật bằng hình thức hạ bậc đẳng, cấp hiện có (hoặc nặng hơn là tước toàn bộ đẳng, cấp và đình chỉ tư cách hội viên)?',NULL,'multi','FREE,BASIC,PRO,VIP','Làm giả hoặc sửa đổi văn bằng: Tự ý sửa đổi các nội dung của văn bằng, hoặc làm bằng gian, bằng giả.','Gian lận thi cử: Có hành vi gian lận trong quá trình tham gia các cuộc thi lên cấp, đẳng.','Vi phạm đạo đức: Vi phạm các quy tắc đạo đức của Liên đoàn Taekwondo Việt Nam.','Tổ chức thi trái phép: Tự ý tổ chức các cuộc thi thăng cấp, đẳng mà không có sự cho phép của Liên đoàn.','Buôn bán, cấp phát bằng không giá trị: Tham gia vào việc mua bán, cho tặng, hoặc cấp các loại văn bằng Taekwondo không có giá trị sử dụng tại Việt Nam (Văn bằng VTF) và trên thế giới (Văn bằng Kukkiwon).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,5,'1,2,3,4,5','Buôn bán, cấp phát bằng không giá trị: Tham gia vào việc mua bán, cho tặng, hoặc cấp các loại văn bằng Taekwondo không có giá trị sử dụng tại Việt Nam (Văn bằng VTF) và trên thế giới (Văn bằng Kukkiwon).||Gian lận thi cử: Có hành vi gian lận trong quá trình tham gia các cuộc thi lên cấp, đẳng.||Làm giả hoặc sửa đổi văn bằng: Tự ý sửa đổi các nội dung của văn bằng, hoặc làm bằng gian, bằng giả.||Tổ chức thi trái phép: Tự ý tổ chức các cuộc thi thăng cấp, đẳng mà không có sự cho phép của Liên đoàn.||Vi phạm đạo đức: Vi phạm các quy tắc đạo đức của Liên đoàn Taekwondo Việt Nam.');
INSERT INTO "question" VALUES (275,24,'Trong nội dung Quyền sáng tạo (Free Style), lứa tuổi "Under 17" bao gồm độ tuổi nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','12 - 17 tuổi','14 - 17 tuổi','15 - 17 tuổi','16 - 18 tuổi',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','12 - 17 tuổi');
INSERT INTO "question" VALUES (276,24,'Đội hình thi đấu Quyền sáng tạo đồng đội (Mixed Team) bao gồm bao nhiêu vận động viên chính thức (không tính dự bị)?',NULL,'mcq','FREE,BASIC,PRO,VIP','5 thành viên ( ít nhất 2 nam hoặc 2 nữ)','6 thành viên ( ít nhất 3 nam hoặc 3 nữ)','5 thành viên (giới tính tự chọn)','6 thành viên (giới tính tự chọn)',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','5 thành viên ( ít nhất 2 nam hoặc 2 nữ)');
INSERT INTO "question" VALUES (277,24,'Đối với lứa tuổi Cadet (12-14), bài quyền nào KHÔNG nằm trong danh sách bài thi chỉ định (Compulsory Poomsae)?',NULL,'mcq','FREE,BASIC,PRO,VIP','Taegeuk sa jang','Koryo','Taebaek','Pyeongwon',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Pyeongwon');
INSERT INTO "question" VALUES (278,24,'Nếu VĐV thực hiện sai bài quyền và phải làm lại từ đầu (Restart), họ sẽ bị trừ bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','0.3 điểm','0.5 điểm','0.6 điểm','Bị loại',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','0.6 điểm');
