INSERT INTO "question" VALUES (280,24,'Số lượng đá liên tục (Consecutive kicks) trong Quyền sáng tạo được giới hạn trong khoảng nào để được tính điểm độ khó?',NULL,'mcq','FREE,BASIC,PRO,VIP','3 đến 5 cái','5 đến 7 cái','7 đến 10 cái','Không giới hạn',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','7 đến 10 cái');
INSERT INTO "question" VALUES (281,24,'Tiêu chí nào sau đây KHÔNG thuộc phần chấm điểm Diễn đạt (Presentation) của Quyền sáng tạo?',NULL,'mcq','FREE,BASIC,PRO,VIP','Sự sáng tạo (Creativity).','Sự hài hòa (Harmony).','Âm nhạc và Vũ đạo (Music & Choreography).','Độ khó của đòn đá (Level of difficulty of kicking).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Độ khó của đòn đá (Level of difficulty of kicking).');
INSERT INTO "question" VALUES (282,24,'Trong Quyền sáng tạo, nếu VĐV thực hiện kỹ thuật không phải là Taekwondo (non-Taekwondo technique), hình thức xử lý là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Không được tính điểm kỹ thuật đó và có thể bị trừ điểm.','Được cộng điểm sáng tạo.','Bị loại ngay lập tức.','Không ảnh hưởng gì.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Không được tính điểm kỹ thuật đó và có thể bị trừ điểm.');
INSERT INTO "question" VALUES (283,24,'Nếu hai VĐV bằng điểm nhau trong nội dung Poomsae Công nhận, tiêu chí đầu tiên để xác định người thắng là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Điểm Diễn đạt (Presentation) cao hơn.','Điểm Chính xác (Accuracy) cao hơn.','Tổng điểm của tất cả trọng tài (kể cả điểm cao nhất/thấp nhất).','Thi lại (Rematch).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Điểm Diễn đạt (Presentation) cao hơn.');
INSERT INTO "question" VALUES (284,24,'Nếu hai VĐV bằng điểm nhau trong nội dung Quyền sáng tạo (Free Style), tiêu chí đầu tiên để xác định người thắng là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Bốc thăm.','Điểm Diễn đạt (Presentation) cao hơn.','Điểm Kỹ thuật (Technical) cao hơn','Trọng tài chính quyết định',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Điểm Kỹ thuật (Technical) cao hơn');
INSERT INTO "question" VALUES (285,24,'Nếu sau khi xét điểm phụ (Presentation/Technical) mà vẫn hòa, tiêu chí tiếp theo là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Tổng điểm của tất cả trọng tài (bao gồm cả điểm cao nhất và thấp nhất đã bị loại bỏ trước đó).','Trọng tài trưởng quyết định.','Thi thêm 1 bài thi phụ','Thi lại bài khác',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Tổng điểm của tất cả trọng tài (bao gồm cả điểm cao nhất và thấp nhất đã bị loại bỏ trước đó).');
INSERT INTO "question" VALUES (286,24,'Nếu vẫn hòa sau khi tính tổng điểm tất cả trọng tài, bước tiếp theo là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Thi đấu lại (Rematch) 1 bài quy định.','Trọng tài trưởng quyết định.','Ban giám sát quyết định.','Tung đồng xu',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Thi đấu lại (Rematch) 1 bài quy định.');
INSERT INTO "question" VALUES (287,23,'Theo Luật thi đấu mới (áp dụng từ 01/01/2026), đòn đá quay (Turning Kick) trúng đầu hợp lệ được tính bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','6 điểm','5 điểm','4 điểm','3 điểm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','6 điểm');
INSERT INTO "question" VALUES (288,23,'Đòn đá quay (Turning Kick) trúng giáp thân hợp lệ được tính bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','5 điểm','4 điểm','3 điểm','2 điểm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','4 điểm');
INSERT INTO "question" VALUES (289,23,'Đòn đá thẳng (không quay) vào vùng đầu được tính bao nhiêu điểm?',NULL,'mcq','FREE,BASIC,PRO,VIP','5 điểm','4 điểm','3 điểm','2 điểm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','3 điểm');
INSERT INTO "question" VALUES (290,23,'Điểm số cho đòn đấm (Punch) trúng đích là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 điểm','2 điểm','3 điểm','4 điểm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','1 điểm');
INSERT INTO "question" VALUES (291,23,'Phương pháp chấm điểm cho đòn đấm (Punch) khi sử dụng găng tay cảm biến (Sensing Gloves) là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Hoàn toàn tự động (PSS đo lực và tính điểm).','Bán tự động (Semi-automatic).','Không tính điểm đấm.','Hoàn toàn thủ công (Trọng tài bấm máy).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','Bán tự động (Semi-automatic).');
INSERT INTO "question" VALUES (292,23,'Có bao nhiêu hạng cân Olympic "Thử nghiệm" (Test Olympic Weight Categories) cho mỗi giới tính trong luật mới?',NULL,'mcq','FREE,BASIC,PRO,VIP','4 hạng cân.','6 hạng cân.','8 hạng cân.','12 hạng cân.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','6 hạng cân.');
INSERT INTO "question" VALUES (293,23,'Các hạng cân Olympic Nam mới (Thử nghiệm) gồm những mức cân nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','-58, -68, -80, +80.','-54, -63, -74, -87, +87.','-54, -60, -67, -74, -82, +82.','-54, -58, -63, -68, -74, +74.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','-54, -60, -67, -74, -82, +82.');
INSERT INTO "question" VALUES (294,23,'Các hạng cân Olympic Nữ mới (Thử nghiệm) gồm những mức cân nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','-49, -57, -67, +67.','-46, -49, -53, -57, -62, -67.','-46, -51, -57, -63, -70, +70.','-46, -53, -62, -73, +73.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','-46, -51, -57, -63, -70, +70.');
INSERT INTO "question" VALUES (295,23,'Một trận đấu Đồng đội (Team Match) theo thể thức Best of 3 gồm bao nhiêu hiệp?',NULL,'mcq','FREE,BASIC,PRO,VIP','1 hiệp duy nhất.','2 hiệp.','3 hiệp.','5 hiệp.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','3 hiệp.');
INSERT INTO "question" VALUES (296,23,'Sau khi đội A thay người, đội B KHÔNG được phép thay người trong vòng bao lâu?',NULL,'mcq','FREE,BASIC,PRO,VIP','10 giây.','15 giây.','20 giây.','D. Được thay ngay lập tức.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','10 giây.');
INSERT INTO "question" VALUES (297,23,'Một đội sẽ bị xử thua (Loser) nếu tích lũy bao nhiêu Gam-jeom trong trận đấu đồng đội?',NULL,'mcq','FREE,BASIC,PRO,VIP','20 Gam-jeom.','30 Gam-jeom.','35 Gam-jeom.','40 Gam-jeom.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','40 Gam-jeom.');
INSERT INTO "question" VALUES (298,23,'Tổng trọng lượng tối đa của Đội Nam (Team of 4 - Senior) là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','300kg.','280kg.','250kg.','230kg.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','300kg.');
INSERT INTO "question" VALUES (299,23,'Tổng trọng lượng tối đa của Đội Nữ (Team of 3 - Senior) là bao nhiêu?',NULL,'mcq','FREE,BASIC,PRO,VIP','250kg.','220kg.','180kg.','200kg.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','200kg.');
INSERT INTO "question" VALUES (300,23,'Đội hình Đồng đội Hỗn hợp (Mixed Team) gồm bao nhiêu VĐV thi đấu trên sân?',NULL,'mcq','FREE,BASIC,PRO,VIP','2 (1 Nam, 1 Nữ).','4 (2 Nam, 2 Nữ).','3 người (phải cso ít nhất 1 nam hoặc 1 nữ).','5 người (phải có ít nhất 2 Nam, 2 Nữ).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','4 (2 Nam, 2 Nữ).');
INSERT INTO "question" VALUES (301,23,'Trong thi đấu Đồng đội Hỗn hợp, VĐV Nam bắt buộc phải mặc quần thi đấu màu gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Màu Đen.','Màu Trắng.','Màu Đỏ.','Màu Xanh.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Màu Đen.');
INSERT INTO "question" VALUES (302,23,'Có áp dụng luật thắng cách biệt điểm số (Point Gap) trong thi đấu đồng đội không?',NULL,'mcq','FREE,BASIC,PRO,VIP','Có, 12 điểm.','Có, 20 điểm.','Không bao giờ dừng.','Không áp dụng Point Gap, nhưng nếu đội đạt 30 điểm trước sẽ thắng hiệp (nếu không dùng Health Bar).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Không áp dụng Point Gap, nhưng nếu đội đạt 30 điểm trước sẽ thắng hiệp (nếu không dùng Health Bar).');
INSERT INTO "question" VALUES (303,23,'Trong thi đấu Đồng đội (Team of 4), nếu 1 VĐV chấn thương, đội có được đá tiếp với 3 người không?',NULL,'mcq','FREE,BASIC,PRO,VIP','Có, nhưng bị trừ 50 điểm.','Phải thay người dự bị ngay lập tức (nếu hết quyền thay thì thua).','Không, xử thua ngay.','Có thể, nếu HLV đồng ý tiếp tục.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Có thể, nếu HLV đồng ý tiếp tục.');
INSERT INTO "question" VALUES (304,23,'Video Replay (IVR) có được sử dụng trong thi đấu Đồng đội không?',NULL,'mcq','FREE,BASIC,PRO,VIP','Không.','Có.','Chỉ trong trận chung kết.','Chỉ cho lỗi hành vi.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Không.');
INSERT INTO "question" VALUES (305,23,'Trọng tài trung tâm CÓ THỂ tự yêu cầu IVR cho tình huống nào sau đây?',NULL,'mcq','FREE,BASIC,PRO,VIP','Xác định lỗi thụ động.','Xác định điểm đá thân.','Kiểm tra trang phục.','Xác định điểm đá đầu khi PSS không ghi nhận nhưng VĐV bị choáng/ngã (Staggering/Knock down) và trọng tài đã đếm.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Xác định điểm đá đầu khi PSS không ghi nhận nhưng VĐV bị choáng/ngã (Staggering/Knock down) và trọng tài đã đếm.');
INSERT INTO "question" VALUES (306,23,'Trong 5 giây cuối hiệp đấu, Trọng tài trung tâm có thể yêu cầu IVR để kiểm tra lỗi nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','Ngã, Ra biên, Tấn công sau lệnh Kal-yeo, Tấn công người đã ngã.','Đòn đấm.','Đòn đá.','Lỗi ôm.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Ngã, Ra biên, Tấn công sau lệnh Kal-yeo, Tấn công người đã ngã.');
INSERT INTO "question" VALUES (307,23,'Nếu HLV khiếu nại sai (bị từ chối), hậu quả là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','HLV bị đuổi khỏi sân.','Không sao cả.','Bị phạt 1 Gam-jeom.','Mất thẻ khiếu nại (Quota) trong trận đó.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Mất thẻ khiếu nại (Quota) trong trận đó.');
INSERT INTO "question" VALUES (308,23,'VĐV Junior/Cadet khi cân được trừ bì bao nhiêu cho trang phục lót?',NULL,'mcq','FREE,BASIC,PRO,VIP','100g.','150g.','200g.','Không có trừ.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','100g.');
INSERT INTO "question" VALUES (309,23,'VĐV bị chấn thương đầu (Concussion) lần đầu tiên sẽ bị đình chỉ thi đấu bắt buộc trong bao lâu (đối với Senior)?',NULL,'mcq','FREE,BASIC,PRO,VIP','20 ngày.','30 ngày.','40 ngày.','60 ngày.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','30 ngày.');
INSERT INTO "question" VALUES (310,23,'VĐV bị chấn thương đầu lần thứ 2 trong vòng 90 ngày sẽ bị đình chỉ bao lâu?',NULL,'mcq','FREE,BASIC,PRO,VIP','30 ngày.','90 ngày.','120 ngày.','1 năm.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','90 ngày.');
INSERT INTO "question" VALUES (311,23,'Tiêu chí đầu tiên để xét ưu thế (Superiority) trong hiệp phụ (Golden Round) nếu hòa điểm là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Số lần chạm giáp (Hits).','Số hiệp thắng trước đó.','Số lỗi Gam-jeom ít hơn.','Điểm ghi được từ đòn Đấm (Punch).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Điểm ghi được từ đòn Đấm (Punch).');
INSERT INTO "question" VALUES (312,23,'Trong thể thức Best of 3, nếu hòa điểm ở một hiệp, tiêu chí ưu thế đầu tiên là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Điểm từ đòn Đấm.','Gam-jeom ít hơn.','Số lần chạm giáp.','Điểm ghi được từ các đòn đá quay/xoay (Turning/Spinning Kick).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Điểm ghi được từ các đòn đá quay/xoay (Turning/Spinning Kick).');
INSERT INTO "question" VALUES (313,23,'Nếu điểm đá quay bằng nhau trong Best of 3, thứ tự ưu tiên tiếp theo là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Điểm Đầu -> Điểm Thân -> Điểm Đấm -> Gam-jeom.','Điểm Đấm -> Điểm Đầu -> Điểm Thân -> Gam-jeom.','Điểm Đấm -> Gam-jeom -> Điểm Đầu -> Điểm Thân.','Gam-jeom -> Điểm Đầu -> Điểm Thân -> Điểm Đấm.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Điểm Đầu -> Điểm Thân -> Điểm Đấm -> Gam-jeom.');
INSERT INTO "question" VALUES (314,23,'Trong thể thức Best of 3, VĐV bị xử thua HIỆP ĐẤU đó nếu nhận bao nhiêu Gam-jeom?',NULL,'mcq','FREE,BASIC,PRO,VIP','3 Gam-jeom.','4 Gam-jeom.','5 Gam-jeom.','6 Gam-jeom.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','5 Gam-jeom.');
INSERT INTO "question" VALUES (315,23,'Nhiệm vụ chính của Trọng tài bàn (Recorder) theo luật định là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Kiểm tra trang phục VĐV.','Theo dõi màn hình Video Replay.','Chấm điểm kỹ thuật cho VĐV.','Tính thời gian thi đấu, thời gian nghỉ, tạm dừng; ghi chép và công bố điểm số/hình phạt.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','Tính thời gian thi đấu, thời gian nghỉ, tạm dừng; ghi chép và công bố điểm số/hình phạt.');
INSERT INTO "question" VALUES (316,23,'Ai là người có nhiệm vụ ghi chép thủ công (manually records) tất cả điểm số, hình phạt và kết quả Video Replay vào biên bản giấy?',NULL,'mcq','FREE,BASIC,PRO,VIP','Trợ lý Kỹ thuật (Technical Assistant - TA).','Giám định (Judge).','Trọng tài bàn (Recorder).','Người vận hành hệ thống PSS (Operator).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','Trợ lý Kỹ thuật (Technical Assistant - TA).');
INSERT INTO "question" VALUES (317,23,'Khi Huấn luyện viên ném khăn vào sân để xin thua cho VĐV của mình, TA sẽ ghi nhận kết quả trận đấu là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','WDR - Win by Withdrawal (Thắng do đối thủ bỏ cuộc).','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).','SUP - Win by Superiority (Thắng ưu thế).','PUN - Win by Punitive Declaration (Thắng do phạt).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','WDR - Win by Withdrawal (Thắng do đối thủ bỏ cuộc).');
INSERT INTO "question" VALUES (318,23,'Trọng tài trung tâm dừng trận đấu vì VĐV bị chấn thương nặng và không thể tiếp tục thi đấu sau 1 phút sơ cứu (không do lỗi phạm quy của đối thủ). TA sẽ tích vào ô nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','DSQ - Win by Disqualification (Thắng do đối thủ bị loại).','WDR - Win by Withdrawal (Thắng do đối thủ bỏ cuộc).','PTF - Win by Final Score (Thắng điểm cuối cùng).','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).');
INSERT INTO "question" VALUES (319,23,'Kết thúc trận đấu (hoặc hiệp đấu), VĐV Xanh thắng VĐV Đỏ với tỷ số điểm 15-10. Kết quả này được gọi là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','DSQ - Win by Disqualification (Thắng do đối thủ bị loại).','PTF - Win by Final Score (Thắng điểm cuối cùng).','WDR - Win by Withdrawal (Thắng do đối thủ bỏ cuộc).','SUP - Win by Superiority (Thắng ưu thế).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','PTF - Win by Final Score (Thắng điểm cuối cùng).');
INSERT INTO "question" VALUES (320,23,'Trong thể thức Best of 3, nếu ở hiệp 1, VĐV Xanh dẫn trước VĐV Đỏ 12 điểm (ví dụ: 14-2). Trọng tài tuyên bố Xanh thắng hiệp đó. Đây là hình thức thắng gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','PTG - Win by Point Gap (Thắng cách biệt điểm số).','PUN - Win by Punitive Declaration (Thắng do phạt).','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).','GDP - Win by Golden Points (Thắng điểm vàng).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','PTG - Win by Point Gap (Thắng cách biệt điểm số).');
INSERT INTO "question" VALUES (321,23,'VĐV Đỏ đã nhận đủ 10 lỗi Gam-jeom trong trận đấu. Trọng tài tuyên bố VĐV Xanh thắng. TA sẽ ghi kết quả là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).','WDR - Win by Withdrawal (Thắng do đối thủ bỏ cuộc).','PUN - Win by Punitive Declaration (Thắng do phạt).','SUP - Win by Superiority (Thắng ưu thế).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','PUN - Win by Punitive Declaration (Thắng do phạt).');
INSERT INTO "question" VALUES (322,23,'VĐV Xanh không đến khu vực kiểm tra (Inspection Desk) sau 3 lần gọi tên và bị loại. TA ghi nhận đối thủ thắng theo hình thức nào?',NULL,'mcq','FREE,BASIC,PRO,VIP','WDR - Win by Withdrawal (Thắng do đối thủ bỏ cuộc).','DSQ - Win by Disqualification (Thắng do đối thủ bị loại).','SUP - Win by Superiority (Thắng ưu thế).','DQB - Win by Disqualification for Unsportsmanlike Behavior (Loại do hành vi phi thể thao).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','DSQ - Win by Disqualification (Thắng do đối thủ bị loại).');
INSERT INTO "question" VALUES (323,23,'Nếu một VĐV bị phát hiện có hành vi gian lận (thay đổi cảm biến PSS) hoặc có hành vi bạo lực nghiêm trọng với trọng tài. Kết quả xử thua nặng nhất này ký hiệu là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','DSQ - Win by Disqualification (Thắng do đối thủ bị loại).','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).','PUN - Win by Punitive Declaration (Thắng do phạt).','DQB - Win by Disqualification for Unsportsmanlike Behavior (Loại do hành vi phi thể thao).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'4','DQB - Win by Disqualification for Unsportsmanlike Behavior (Loại do hành vi phi thể thao).');
INSERT INTO "question" VALUES (324,23,'Trong Hiệp phụ (Golden Round), VĐV Xanh ghi được 2 điểm trước và chiến thắng. Kết quả này TA sẽ ghi là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','GDP - Win by Golden Points (Thắng điểm vàng).','DSQ - Win by Disqualification (Thắng do đối thủ bị loại).','SUP - Win by Superiority (Thắng ưu thế).','PTG - Win by Point Gap (Thắng cách biệt điểm số).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'1','GDP - Win by Golden Points (Thắng điểm vàng).');
INSERT INTO "question" VALUES (325,23,'Kết thúc Hiệp phụ (hoặc hiệp đấu chính hòa điểm), không ai ghi điểm vàng. Trọng tài và giám định bầu chọn cho VĐV Đỏ thắng nhờ ưu thế. TA ghi kết quả là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','RSC - Referee Stops Contest (Trọng tài dừng trận đấu).','SUP - Win by Superiority (Thắng ưu thế).','PUN - Win by Punitive Declaration (Thắng do phạt).','PTF - Win by Final Score (Thắng điểm cuối cùng).',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'2','SUP - Win by Superiority (Thắng ưu thế).');
INSERT INTO "question" VALUES (326,23,'Nhiệm vụ quan trọng nhất của TA liên quan đến "TA Paper" (Biên bản giấy) là gì?',NULL,'mcq','FREE,BASIC,PRO,VIP','Dùng để kiểm tra và nghiên cứu','Chỉ dùng để nháp, không quan trọng.','Ghi chép thủ công tất cả điểm số, hình phạt và kết quả IVR để đối chiếu khi hệ thống điện tử gặp sự cố.','Dùng để HLV ký tên khiếu nại.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,4,'3','Ghi chép thủ công tất cả điểm số, hình phạt và kết quả IVR để đối chiếu khi hệ thống điện tử gặp sự cố.');
